56	/***********************************************************************
57	 * Reusable managed receiver buffer:
58	 *  - get_new performs the recv operation
59	 **********************************************************************/
60	class udp_zero_copy_asio_mrb : public managed_recv_buffer
61	{
62	public:
63	    udp_zero_copy_asio_mrb(void* mem, int sock_fd, const size_t frame_size)
64	        : _mem(mem), _sock_fd(sock_fd), _frame_size(frame_size), _len(0)
65	    { /*NOP*/
66	    }
67	
68	    void release(void) override
69	    {
70	        _claimer.release();
71	    }
72	
73	    UHD_INLINE sptr get_new(const double timeout, size_t& index)
74	    {
75	        if (not _claimer.claim_with_wait(timeout))
76	            return sptr();
77	
78	        const int32_t timeout_ms = static_cast<int32_t>(timeout * 1000);
79	        _len = recv_udp_packet(_sock_fd, _mem, _frame_size, timeout_ms);
80	
81	        if (_len > 0) {
82	            index++;
83	            return make(this, _mem, size_t(_len));
84	        }
85	
86	        _claimer.release(); // undo claim
87	        return sptr(); // null for timeout
88	    }
89	
90	private:
91	    void* _mem;
92	    int _sock_fd;
93	    size_t _frame_size;
94	    ssize_t _len;
95	    simple_claimer _claimer;
96	};
97	
98	/***********************************************************************
99	 * Reusable managed send buffer:
100	 *  - commit performs the send operation
101	 **********************************************************************/
102	class udp_zero_copy_asio_msb : public managed_send_buffer
103	{
104	public:
105	    udp_zero_copy_asio_msb(void* mem, int sock_fd, const size_t frame_size)
106	        : _mem(mem), _sock_fd(sock_fd), _frame_size(frame_size)
107	    { /*NOP*/
108	    }
109	
110	    void release(void) override
111	    {
112	        send_udp_packet(_sock_fd, _mem, size());
113	        _claimer.release();
114	    }
115	
116	    UHD_INLINE sptr get_new(const double timeout, size_t& index)
117	    {
118	        if (not _claimer.claim_with_wait(timeout))
119	            return sptr();
120	        index++; // advances the caller's buffer
121	        return make(this, _mem, _frame_size);
122	    }
123	
124	private:
125	    void* _mem;
126	    int _sock_fd;
127	    size_t _frame_size;
128	    simple_claimer _claimer;
129	};
