55	    size_t recv(const asio::mutable_buffer& buff, double timeout) override
56	    {
57	        const int32_t timeout_ms = static_cast<int32_t>(timeout * 1000);
58	
59	        if (not wait_for_recv_ready(_socket->native_handle(), timeout_ms))
60	            return 0;
61	        return _socket->receive_from(asio::buffer(buff), _recv_endpoint);
62	    }
