106	class udp_simple_uart_impl : public uhd::uart_iface
107	{
108	public:
109	    udp_simple_uart_impl(udp_simple::sptr udp)
110	    {
111	        _udp = udp;
112	        _len = 0;
113	        _off = 0;
114	        this->write_uart(""); // send an empty packet to init
115	    }
116	
117	    void write_uart(const std::string& buf) override
118	    {
119	        _udp->send(asio::buffer(buf));
120	    }
121	
122	    std::string read_uart(double timeout) override
123	    {
124	        std::string line;
125	        const boost::system_time exit_time =
126	            boost::get_system_time()
127	            + boost::posix_time::milliseconds(long(timeout * 1000));
128	        do {
129	            // drain anything in current buffer
130	            while (_off < _len) {
131	                const char ch = _buf[_off++];
132	                _line += ch;
133	                if (ch == '\n') {
134	                    line.swap(_line);
135	                    return line;
136	                }
137	            }
138	
139	            // recv a new packet into the buffer
140	            _len = _udp->recv(asio::buffer(_buf),
141	                std::max(
142	                    (exit_time - boost::get_system_time()).total_milliseconds() / 1000.,
143	                    0.0));
144	            _off = 0;
145	
146	        } while (_len != 0);
147	        return line;
148	    }
149	
150	private:
151	    udp_simple::sptr _udp;
152	    size_t _len, _off;
153	    uint8_t _buf[udp_simple::mtu];
154	    std::string _line;
155	};
