44	/*!
45	 * Wait for the socket to become ready for a receive operation.
46	 * \param sock_fd the open socket file descriptor
47	 * \param timeout_ms the timeout duration in milliseconds
48	 * \return true when the socket is ready for receive
49	 */
50	UHD_INLINE bool wait_for_recv_ready(int sock_fd, int32_t timeout_ms)
51	{
52	#ifdef UHD_PLATFORM_WIN32 // select is more portable than poll unfortunately
53	    // setup timeval for timeout
54	    timeval tv;
55	    // If the tv_usec > 1 second on some platforms, select will
56	    // error EINVAL: An invalid timeout interval was specified.
57	    tv.tv_sec  = int(timeout_ms / 1000);
58	    tv.tv_usec = int(timeout_ms * 1000) % 1000000;
59	
60	    // setup rset for timeout
61	    fd_set rset;
62	    FD_ZERO(&rset);
63	    FD_SET(sock_fd, &rset);
64	
65	// http://www.gnu.org/s/hello/manual/libc/Interrupted-Primitives.html
66	// This macro is provided with gcc to properly deal with EINTR.
67	// If not provided, define an empty macro, assume that is OK
68	#    ifndef TEMP_FAILURE_RETRY
69	#        define TEMP_FAILURE_RETRY(x) (x)
70	#    endif
71	
72	    // call select with timeout on receive socket
73	    return TEMP_FAILURE_RETRY(::select(sock_fd + 1, &rset, NULL, NULL, &tv)) > 0;
74	#else
75	    pollfd pfd_read;
76	    pfd_read.fd     = sock_fd;
77	    pfd_read.events = POLLIN;
78	
79	    // call poll with timeout on receive socket
80	    return ::poll(&pfd_read, 1, (int)timeout_ms) > 0;
81	#endif
82	}
